#!/usr/bin/env python3
"""
可视化 GroundingME 评估结果
处理图片路径在单独目录的情况
"""

import json
import os
from pathlib import Path
from typing import Dict, List, Any
import argparse
from PIL import Image, ImageDraw, ImageFont
from tqdm import tqdm
import random

def find_image_path(
    image_filename: str,
    image_dirs: List[str]
) -> str:
    """
    在多个可能的目录中查找图片

    Args:
        image_filename: 图片文件名或相对路径
        image_dirs: 可能的图片目录列表

    Returns:
        找到的完整图片路径，如果找不到返回None
    """
    # 提取文件名（去掉路径）
    basename = os.path.basename(image_filename)

    # 在每个目录中查找
    for img_dir in image_dirs:
        # 尝试直接拼接
        candidate = os.path.join(img_dir, basename)
        if os.path.exists(candidate):
            return candidate

        # 尝试保留原始相对路径
        candidate = os.path.join(img_dir, image_filename)
        if os.path.exists(candidate):
            return candidate

    return None

def draw_bbox_comparison(
    image_path: str,
    pred_bbox: List[float],
    gt_bbox: List[float],
    sample_info: Dict[str, Any],
    output_path: str,
    show_text: bool = True
):
    """在图像上绘制预测框和真实框"""
    try:
        image = Image.open(image_path).convert('RGB')
    except Exception as e:
        print(f"Error loading image {image_path}: {e}")
        return False

    draw = ImageDraw.Draw(image)

    # 加载字体
    try:
        font = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf", 28)
        small_font = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", 20)
    except:
        try:
            # 尝试其他常见字体路径
            font = ImageFont.truetype("/System/Library/Fonts/Helvetica.ttc", 28)
            small_font = ImageFont.truetype("/System/Library/Fonts/Helvetica.ttc", 20)
        except:
            font = ImageFont.load_default()
            small_font = ImageFont.load_default()

    # 绘制真实框（绿色，粗线）
    if gt_bbox and gt_bbox != [0, 0, 0, 0]:
        draw.rectangle(gt_bbox, outline='#00FF00', width=5)
        draw.text((gt_bbox[0], gt_bbox[1] - 35), "Ground Truth", fill='#00FF00', font=font)

    # 绘制预测框（红色）
    if pred_bbox and pred_bbox != [0, 0, 0, 0]:
        draw.rectangle(pred_bbox, outline='#FF0000', width=5)
        draw.text((pred_bbox[0], pred_bbox[1] - 70), "Prediction", fill='#FF0000', font=font)

    # 添加信息栏
    if show_text:
        iou = sample_info.get('iou', 0)
        acc_50 = sample_info.get('acc_50', 0)
        sample_id = sample_info.get('id', 'N/A')

        # 根据IoU选择颜色
        if iou >= 0.5:
            text_color = '#00FF00'  # 绿色
            status = "✓ PASS"
        elif iou >= 0.25:
            text_color = '#FFA500'  # 橙色
            status = "⚠ LOW"
        else:
            text_color = '#FF0000'  # 红色
            status = "✗ FAIL"

        # 创建信息栏
        info_height = 80
        info_bg = Image.new('RGB', (image.width, info_height), color='#2C3E50')
        info_draw = ImageDraw.Draw(info_bg)

        # 绘制信息文本
        info_text = f"Sample ID: {sample_id}  |  IoU: {iou:.4f}  |  ACC@0.5: {int(acc_50)}  |  {status}"
        info_draw.text((15, 25), info_text, fill=text_color, font=font)

        # 合并图像
        result = Image.new('RGB', (image.width, image.height + info_height))
        result.paste(info_bg, (0, 0))
        result.paste(image, (0, info_height))
        image = result

    # 保存
    os.makedirs(os.path.dirname(output_path), exist_ok=True)
    image.save(output_path, quality=95)
    return True

def visualize_results(
    results_json: str,
    dataset_json: str,
    image_dirs: List[str],
    output_dir: str,
    max_samples: int = None,
    filter_by: str = None,
    filter_value: float = None
):
    """批量可视化评估结果"""
    print(f"Loading results from {results_json}...")
    with open(results_json, 'r') as f:
        results = json.load(f)

    print(f"Loading dataset from {dataset_json}...")
    with open(dataset_json, 'r') as f:
        dataset = json.load(f)

    # 创建 ID 到图像文件名的映射
    id_to_image = {}
    for item in dataset:
        sample_id = item.get('id')
        image_path = item.get('image')
        if sample_id is not None and image_path:
            id_to_image[sample_id] = image_path

    print(f"Image directories to search: {image_dirs}")

    detailed_results = results.get('detailed_results', [])

    # 过滤样本
    filtered_results = []
    if filter_by == 'iou' and filter_value is not None:
        filtered_results = [r for r in detailed_results if r['iou'] < filter_value]
        print(f"Filtering samples with IoU < {filter_value}")
    elif filter_by == 'acc_50':
        filtered_results = [r for r in detailed_results if r['acc_50'] == 0]
        print(f"Filtering samples with ACC@0.5 = 0")
    elif filter_by == 'good':
        filtered_results = [r for r in detailed_results if r['iou'] >= 0.5]
        print(f"Filtering samples with IoU >= 0.5")
    else:
        filtered_results = detailed_results
        print("Visualizing all samples")

    # 限制数量
    if max_samples and len(filtered_results) > max_samples:
        print(f"Randomly sampling {max_samples} from {len(filtered_results)} filtered samples")
        random.seed(42)  # 固定随机种子以便复现
        filtered_results = random.sample(filtered_results, max_samples)

    print(f"\nVisualizing {len(filtered_results)} samples...")

    # 创建输出目录
    os.makedirs(output_dir, exist_ok=True)

    # 统计
    success_count = 0
    failed_count = 0
    not_found_count = 0

    # 批量处理
    for result in tqdm(filtered_results, desc="Visualizing"):
        sample_id = result['id']

        # 获取图像文件名
        image_filename = id_to_image.get(sample_id)
        if not image_filename:
            print(f"\nWarning: Image filename not found for sample {sample_id}")
            not_found_count += 1
            continue

        # 在多个目录中查找图像
        image_path = find_image_path(image_filename, image_dirs)

        if not image_path:
            print(f"\nWarning: Image file not found: {image_filename}")
            print(f"  Searched in: {image_dirs}")
            not_found_count += 1
            continue

        # 构造输出路径
        iou = result['iou']
        acc = result['acc_50']
        # 使用更清晰的文件名
        status = "pass" if acc == 1 else "fail"
        output_filename = f"id{sample_id}_{status}_iou{iou:.3f}.jpg"
        output_path = os.path.join(output_dir, output_filename)

        # 绘制
        success = draw_bbox_comparison(
            image_path=image_path,
            pred_bbox=result['pred_bbox'],
            gt_bbox=result['gt_bbox'],
            sample_info=result,
            output_path=output_path,
            show_text=True
        )

        if success:
            success_count += 1
        else:
            failed_count += 1

    print(f"\n{'='*60}")
    print(f"Visualization complete!")
    print(f"  Success: {success_count}")
    print(f"  Failed: {failed_count}")
    print(f"  Not found: {not_found_count}")
    print(f"  Output directory: {output_dir}")
    print(f"{'='*60}")

